mapper.select:
select ri.id, ri.room_number, ri.rent, ri.apartment_id, ri.publisher_type, ri.publisher_id, ri.is_release, ri.review_status, ri.compliance_score, ri.last_reviewed_at, ri.create_time, ri.update_time, ( SELECT rr.overall_rating FROM room_review rr WHERE rr.room_id = ri.id AND rr.is_deleted = 0 AND rr.status = 2 ORDER BY rr.create_time DESC LIMIT 1 ) as overall_rating, ai.id apartment_id, ai.name apartment_name, ai.introduction, ai.district_id, ai.district_name, ai.city_id, ai.city_name, ai.province_id, ai.province_name, ai.address_detail, ai.latitude, ai.longitude, ai.phone, ai.is_release apartment_is_release from room_info ri left join apartment_info ai on ri.apartment_id = ai.id and ai.is_deleted = 0
ri.is_deleted = 0
and ri.publisher_type = #{queryVo.publisherType} and ri.publisher_id = #{queryVo.publisherId}
and ri.is_release = 1 and ri.review_status = 2 and ri.id not in( select room_id from lease_agreement where is_deleted = 0 and status in(2,5))
and ri.apartment_id = #{queryVo.apartmentId}
and ai.province_id = #{queryVo.provinceId}
and ai.city_id = #{queryVo.cityId}
and ai.district_id = #{queryVo.districtId}
and (ri.rent >= #{queryVo.minRent} and ri.rent <= #{queryVo.maxRent})
and ri.id in ( select room_id from room_payment_type where is_deleted = 0 and payment_type_id = #{queryVo.paymentTypeId} )
and ri.is_release = #{queryVo.isRelease}
and ri.review_status = #{queryVo.reviewStatus}
and ri.publisher_type = #{queryVo.publisherType}
order by ri.rent ${queryVo.orderType}
order by ri.create_time desc
